function createBaseEnvelope(): Envelope {
  return {
    protocolVersion: 0,
    requestId: "",
    startupNonce: Buffer.alloc(0),
    deadlineUnixMs: 0n,
    idempotencyKey: "",
    payload: undefined,
  };
}

export const Envelope: MessageFns<Envelope> = {
  encode(message: Envelope, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.protocolVersion !== 0) {
      writer.uint32(8).uint32(message.protocolVersion);
    }
    if (message.requestId !== "") {
      writer.uint32(18).string(message.requestId);
    }
    if (message.startupNonce.length !== 0) {
      writer.uint32(26).bytes(message.startupNonce);
    }
    if (message.deadlineUnixMs !== 0n) {
      if (BigInt.asUintN(64, message.deadlineUnixMs) !== message.deadlineUnixMs) {
        throw new globalThis.Error("value provided for field message.deadlineUnixMs of type uint64 too large");
      }
      writer.uint32(32).uint64(message.deadlineUnixMs);
    }
    if (message.idempotencyKey !== "") {
      writer.uint32(42).string(message.idempotencyKey);
    }
    switch (message.payload?.$case) {
      case "request":
        Request.encode(message.payload.value, writer.uint32(82).fork()).join();
        break;
      case "response":
        Response.encode(message.payload.value, writer.uint32(90).fork()).join();
        break;
      case "event":
        Event.encode(message.payload.value, writer.uint32(98).fork()).join();
        break;
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): Envelope {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseEnvelope();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 8) {
            break;
          }

          message.protocolVersion = reader.uint32();
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.requestId = reader.string();
          continue;
        }
        case 3: {
          if (tag !== 26) {
            break;
          }

          message.startupNonce = Buffer.from(reader.bytes());
          continue;
        }
        case 4: {
          if (tag !== 32) {
            break;
          }

          message.deadlineUnixMs = reader.uint64() as bigint;
          continue;
        }
        case 5: {
          if (tag !== 42) {
            break;
          }

          message.idempotencyKey = reader.string();
          continue;
        }
        case 10: {
          if (tag !== 82) {
            break;
          }

          message.payload = { $case: "request", value: Request.decode(reader, reader.uint32()) };
          continue;
        }
        case 11: {
          if (tag !== 90) {
            break;
          }

          message.payload = { $case: "response", value: Response.decode(reader, reader.uint32()) };
          continue;
        }
        case 12: {
          if (tag !== 98) {
            break;
          }

          message.payload = { $case: "event", value: Event.decode(reader, reader.uint32()) };
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  create(base?: DeepPartial<Envelope>): Envelope {
    return Envelope.fromPartial(base ?? {});
  },
  fromPartial(object: DeepPartial<Envelope>): Envelope {
    const message = createBaseEnvelope();
    message.protocolVersion = object.protocolVersion ?? 0;
    message.requestId = object.requestId ?? "";
    message.startupNonce = object.startupNonce ?? Buffer.alloc(0);
    message.deadlineUnixMs = (object.deadlineUnixMs !== undefined && object.deadlineUnixMs !== null)
      ? BigInt(object.deadlineUnixMs)
      : 0n;
    message.idempotencyKey = object.idempotencyKey ?? "";
    switch (object.payload?.$case) {
      case "request": {
        if (object.payload?.value !== undefined && object.payload?.value !== null) {
          message.payload = { $case: "request", value: Request.fromPartial(object.payload.value) };
        }
        break;
      }
      case "response": {
        if (object.payload?.value !== undefined && object.payload?.value !== null) {
          message.payload = { $case: "response", value: Response.fromPartial(object.payload.value) };
        }
        break;
      }
      case "event": {
        if (object.payload?.value !== undefined && object.payload?.value !== null) {
          message.payload = { $case: "event", value: Event.fromPartial(object.payload.value) };
        }
        break;
      }
    }
    return message;
  },
};

function createBaseRequest(): Request {
  return { operation: undefined };
}

